# File: plot_results.py
import pandas as pd
import matplotlib.pyplot as plt
import numpy as np
import os

# Ensure the script can find the CSV generated by the C++ engine
csv_path = 'build/rsw_results.csv' 
if not os.path.exists(csv_path):
    # Fallback if the exe ran in the root directory
    csv_path = 'rsw_results.csv'

try:
    df = pd.read_csv(csv_path)
except FileNotFoundError:
    print(f"Error: Could not find {csv_path}. Make sure to run the C++ engine first!")
    exit()

# Set up a professional, dark-mode Quant aesthetic
plt.style.use('dark_background')
fig, ax = plt.subplots(figsize=(8, 5))

x = np.arange(len(df['Feature']))
width = 0.35

# Plot the bars
rects1 = ax.bar(x - width/2, df['True_Weight'], width, label='True Environment (Hidden)', color='#00ffcc')
rects2 = ax.bar(x + width/2, df['Learned_Weight'], width, label='RSW Engine Output', color='#ff3366')

# Formatting
ax.set_ylabel('Feature Weight (Impact on Strategy)')
ax.set_title('RiskRM / RSW: Spurious Correlation Elimination', pad=20, fontsize=14, fontweight='bold')
ax.set_xticks(x)
ax.set_xticklabels(['True Signal (S)', 'Spurious Trap (V)'], fontsize=12)
ax.legend()

# Add the exact numbers on top of the bars
ax.bar_label(rects1, padding=3, fmt='%.2f')
ax.bar_label(rects2, padding=3, fmt='%.4f')

plt.tight_layout()
plt.savefig('benchmark_plot.png', dpi=300)
print("[SUCCESS] Visualization saved as benchmark_plot.png")